        // resets the in-flight wizard accumulator.
        def stPageInputs = [
            [name: "cond", type: "enum", options: ["": "Click to set", "a": "--> New Condition", "b": "--> ( sub-expression"]],
            [name: "doneST", type: "button"]
        ]
