                capability: "Temperature",
                deviceIds: [8],
                attribute: "setpoint",
                comparator: ">",
                value: 70
            ]]],
            confirm: true
        ])

        then: "the comparator RelrDev_1 IS written on the free path -- enum-suppress did not over-fire"
        result.success == true
