                body.each { k, v ->
                    def key = _settingKeyOf(k)
                    if (key != null) {
                        writtenFields[key] = v
                        if (key == "rCapab_1")   rCapabWritten = true
                        if (key == "starting1")  startingWritten = true
                        if (key == "startingA1") startingAWritten = true
                        if (key == "ending1")    endingWritten = true
                    }
                }
            }
            [status: 200, location: null, data: '']
        }
