            [status: 200, location: null, data: '']
        }

        when:
        def result = script.toolSetRule([
            appId: 100,
            patches: [[removeAction: [index: 1]]],
            confirm: true
        ])

        then: "patch entry succeeds with the rich-return slots populated"
